"""Registry of (dataset, column) sources for the OnPair compression benchmark.

Adding a new column is a one-line append to ``COLUMNS``.

Source kinds:

* ``tpch``    — generated locally via the Rust ``gen-tpch`` subcommand (all
                tables, one parquet file each). Set ``table`` + ``column``.
* ``parquet`` — an already-present parquet file (downloaded or generated by
                other means); give its path via ``parquet``.

``run.py`` validates each column against the parquet schema and silently skips
any that are missing or non-string, so over-broad lists are safe.
"""

from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path

# vortex-bench/data — matches `data_dir()` in the Rust crate.
REPO_ROOT = Path(__file__).resolve().parents[2]
DATA_DIR = REPO_ROOT / "vortex-bench" / "data"
SRC_DIR = DATA_DIR / "onpair-bench-src"

# Local datasets already on disk.
CLICKBENCH_HITS = Path("/home/joe/data/hits.parquet")
FINEWEB_PARQUET = Path("/home/joe/data/fineweb/sample_10BT_combined.parquet")
# Amazon book reviews — the free-text corpus from the original OnPair paper.
BOOK_REVIEWS_PARQUET = Path("/home/joe/data/book_reviews/book_reviews.parquet")


@dataclass
class Column:
    """One column to benchmark."""

    dataset_id: str
    column: str
    kind: str  # "tpch" | "parquet"
    # tpch
    scale_factor: float = 10.0
    table: str = "lineitem"
    # parquet
    parquet: Path | None = None

    def tpch_dir(self) -> Path:
        return SRC_DIR / f"tpch_sf{int(self.scale_factor)}"

    def parquet_path(self) -> Path:
        if self.kind == "tpch":
            return self.tpch_dir() / "parquet" / f"{self.table}_0.parquet"
        if self.kind == "parquet":
            assert self.parquet is not None
            return Path(self.parquet)
        raise ValueError(f"unknown source kind {self.kind!r}")


# Every TPC-H string column, by table. Single-char / few-value columns
# (returnflag, linestatus, orderstatus, mktsegment, brand, ...) are intentionally
# included: they show OnPair *expanding* low-cardinality data, where a value
# dictionary wins.
_TPCH_STR_COLS: dict[str, list[str]] = {
    "region": ["r_name", "r_comment"],
    "nation": ["n_name", "n_comment"],
    "supplier": ["s_name", "s_address", "s_phone", "s_comment"],
    "customer": ["c_name", "c_address", "c_phone", "c_mktsegment", "c_comment"],
    "part": ["p_name", "p_mfgr", "p_brand", "p_type", "p_container", "p_comment"],
    "partsupp": ["ps_comment"],
    "orders": ["o_orderstatus", "o_orderpriority", "o_clerk", "o_comment"],
    "lineitem": ["l_returnflag", "l_linestatus", "l_shipinstruct", "l_shipmode", "l_comment"],
}

_CLICKBENCH_STR_COLS = ["URL", "Title", "Referer", "SearchPhrase", "MobilePhoneModel"]

# FineWeb: long free text + URLs + low-cardinality categoricals.
_FINEWEB_STR_COLS = ["text", "url", "file_path", "dump", "language"]

# The benchmark registry. Append a one-line `Column(...)` to grow the suite.
COLUMNS: list[Column] = [
    *(
        Column(dataset_id="tpch-sf10", column=c, kind="tpch", scale_factor=10.0, table=t)
        for t, cols in _TPCH_STR_COLS.items()
        for c in cols
    ),
    *(
        Column(dataset_id="clickbench", column=c, kind="parquet", parquet=CLICKBENCH_HITS)
        for c in _CLICKBENCH_STR_COLS
    ),
    *(
        Column(dataset_id="fineweb", column=c, kind="parquet", parquet=FINEWEB_PARQUET)
        for c in _FINEWEB_STR_COLS
    ),
    # OnPair paper's book-reviews corpus (single `text` column).
    Column(dataset_id="book-reviews", column="text", kind="parquet",
           parquet=BOOK_REVIEWS_PARQUET),
]
